__*/_jsxs("div",{className:"dr",children:[/*#__PURE__*/_jsx("span",{className:"dl",children:"Sigma deviation"}),/*#__PURE__*/_jsxs("span",{className:"dv",children:["\u03C3 = ",selectedStation.sg.toFixed(1)," \xB7 conf ",Math.min(98,Math.round(60+selectedStation.sg*8)),"%"]})]}),/*#__PURE__*/_jsxs("div",{className:"dr",children:[/*#__PURE__*/_jsx("span",{className:"dl",children:"Coordinates"}),/*#__PURE__*/_jsxs("span",{className:"dv",children:[selectedStation.la.toFixed(3),"\xB0N ",selectedStation.lo.toFixed(3),"\xB0E"]})]})]}),/*#__PURE__*/_jsx("button",{className:"abtn",onClick:runSentinel2Scrape,disabled:loading,children:loading?'Loading...':'Scrape Sentinel-2 for this point →'}),scrapeSummary&&/*#__PURE__*/_jsx("div",{className:"scrape-status",children:scrapeSummary})]})]})]})]});};export default WaterWatchMap;

